#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <dirent.h>
#include <sys/stat.h>
#include <readline/readline.h>
#include <readline/history.h>
#include "../include/builtins.h"
#include "../include/shell.h"



static Alias alias_table[MAX_ALIASES];
static i32 alias_count = 0;



i32 builtin_history(char **args) {
    (void)args;
    HIST_ENTRY **hist = history_list();
    if (!hist) {
        printf("mikush: No history available.\n");
        return 0;
    }
    
    for (i32 i = 0; hist[i]; i++) {
        printf("%s%4d%s  %s\n",
            COLOR_MIKU,
            i + history_base,
            COLOR_RESET,
            hist[i]->line
        );    
    }
    return 0;
}



i32 builtin_cd(char **args) {
    char *dir = args[1] ? args[1] : getenv("HOME");
    if (chdir(dir) != 0) {
        perror("mikush");
        return 1;
    }
    return 0;
}

i32 builtin_pwd(char **args) {
    (void)args;
    char *path = getcwd(NULL, 0);
    if (!path) {
        perror("mikush");
        return 1;
    }
    printf("%s\n", path);
    free(path);
    return 0;
}



i32 builtin_alias(char **args) {
    if (!args[1]) {
        for (i32 i = 0; i < alias_count; i++)
            printf("alias %s='%s'\n", alias_table[i].name, alias_table[i].value);
        return 0;
    }

    char *eq = strchr(args[1], '=');
    if (!eq) {
        fprintf(stderr, "mikush: alias: usage: alias name=value\n");
        return 1;
    }

    *eq = '\0';
    char *name  = args[1];
    char *value = eq + 1;

    for (i32 i = 0; i < alias_count; i++) {
        if (strcmp(alias_table[i].name, name) == 0) {
            free(alias_table[i].value);
            alias_table[i].value = strdup(value);
            return 0;
        }
    }

    if (alias_count >= MAX_ALIASES) {
        fprintf(stderr, "mikush: alias table full\n");
        return 1;
    }

    alias_table[alias_count].name  = strdup(name);
    alias_table[alias_count].value = strdup(value);
    alias_count++;
    return 0;
}

i32 builtin_unalias(char **args) {
    if (!args[1]) {
        fprintf(stderr, "mikush: unalias: usage: unalias name\n");
        return 1;
    }

    for (i32 i = 0; i < alias_count; i++) {
        if (strcmp(alias_table[i].name, args[1]) == 0) {
            free(alias_table[i].name);
            free(alias_table[i].value);
            alias_table[i] = alias_table[--alias_count];
            return 0;
        }
    }

    fprintf(stderr, "mikush: unalias: %s: not found\n", args[1]);
    return 1;
}

i32 builtin_help(char **args) {
    (void)args;
    printf("mikush v%s — 🌸 ようこそ\n", MIKUSH_VERSION);
    printf("Built-in commands:\n");
    printf("  cd [dir]       Change directory to 'dir' or HOME if not specified\n");
    printf("  pwd            Print current working directory\n");
    printf("  history        Show command history\n");
    printf("  alias [name=value]   Create an alias or list all aliases\n");
    printf("  unalias name   Remove an alias\n");
    printf("  help           Show this help message\n");
    printf("  exit           Exit the shell\n");
    return 0;
}


i32 builtin_sing(char **args) {
    (void)args;
    printf("🎤 La la la, singing a song! 🎶\n");
    return 0;
}


